using System;

class Calculator
{
    public int Add(int a, int b)
    {
        return a + b;
    }

    public double Add(double a, double b)
    {
        return a + b;
    }

    public int Add(int a, int b, int c)
    {
        return a + b + c;
    }
}

class Program
{
    static void Main(string[] args)
    {
        Calculator calc = new Calculator();
        Console.WriteLine($"İki tam ədəd: {calc.Add(5, 3)}");
        Console.WriteLine($"İki onluq ədəd: {calc.Add(5.5, 3.2)}");
        Console.WriteLine($"Üç tam ədəd: {calc.Add(5, 3, 2)}");
    }
}
// Output:
// İki tam ədəd: 8
// İki onluq ədəd: 8.7
// Üç tam ədəd: 10

using System;

class Shape
{
    public virtual void Draw()
    {
        Console.WriteLine("Fiqur çəkilir.");
    }
}

class Circle : Shape
{
    public override void Draw()
    {
        Console.WriteLine("Dairə çəkilir.");
    }
}

class Rectangle : Shape
{
    public override void Draw()
    {
        Console.WriteLine("Düzbucaqlı çəkilir.");
    }
}

class Program
{
    static void Main(string[] args)
    {
        Shape shape = new Shape();
        Shape circle = new Circle();
        Shape rectangle = new Rectangle();

        shape.Draw();
        circle.Draw();
        rectangle.Draw();
    }
}
// Output:
// Fiqur çəkilir.
// Dairə çəkilir.
// Düzbucaqlı çəkilir.

